14	 *  WHATSOEVER RESULTING FROM LOSS OF USE, DATA OR PROFITS, WHETHER IN AN
15	 *  ACTION OF CONTRACT, NEGLIGENCE OR OTHER TORTIOUS ACTION, ARISING OUT OF
16	 *  OR IN CONNECTION WITH THE USE OR PERFORMANCE OF THIS SOFTWARE.
17	 *
18	 */
19	
20	module spimemio (
21		input clk, resetn,
22	
23		input valid,
24		output ready,
25		input [23:0] addr,
26		output reg [31:0] rdata,
27	
28		output flash_csb,
29		output flash_clk,
30	
31		output flash_io0_oe,
32		output flash_io1_oe,
33		output flash_io2_oe,
34		output flash_io3_oe,
35	
36		output flash_io0_do,
37		output flash_io1_do,
38		output flash_io2_do,
39		output flash_io3_do,
40	
41		input  flash_io0_di,
42		input  flash_io1_di,
43		input  flash_io2_di,
44		input  flash_io3_di,
45	
46		input   [3:0] cfgreg_we,
47		input  [31:0] cfgreg_di,
48		output [31:0] cfgreg_do
49	);
50		reg        xfer_resetn;
51		reg        din_valid;
52		wire       din_ready;
53		reg  [7:0] din_data;
54		reg  [3:0] din_tag;
55		reg        din_cont;
56		reg        din_qspi;
57		reg        din_ddr;
58		reg        din_rd;
59	
60		wire       dout_valid;
61		wire [7:0] dout_data;
62		wire [3:0] dout_tag;
63	
64		reg [23:0] buffer;
65	
66		reg [23:0] rd_addr;
67		reg rd_valid;
68		reg rd_wait;
69		reg rd_inc;
70	
71		assign ready = valid && (addr == rd_addr) && rd_valid;
72		wire jump = valid && !ready && (addr != rd_addr+4) && rd_valid;
73	
74		reg softreset;
75	
76		reg       config_en;      // cfgreg[31]
77		reg       config_ddr;     // cfgreg[22]
78		reg       config_qspi;    // cfgreg[21]
79		reg       config_cont;    // cfgreg[20]
80		reg [3:0] config_dummy;   // cfgreg[19:16]
81		reg [3:0] config_oe;      // cfgreg[11:8]
82		reg       config_csb;     // cfgreg[5]
83		reg       config_clk;     // cfgref[4]
84		reg [3:0] config_do;      // cfgreg[3:0]
85	
86		assign cfgreg_do[31] = config_en;
87		assign cfgreg_do[30:23] = 0;
88		assign cfgreg_do[22] = config_ddr;
89		assign cfgreg_do[21] = config_qspi;
90		assign cfgreg_do[20] = config_cont;
91		assign cfgreg_do[19:16] = config_dummy;
92		assign cfgreg_do[15:12] = 0;
93		assign cfgreg_do[11:8] = {flash_io3_oe, flash_io2_oe, flash_io1_oe, flash_io0_oe};
94		assign cfgreg_do[7:6] = 0;
95		assign cfgreg_do[5] = flash_csb;
96		assign cfgreg_do[4] = flash_clk;
97		assign cfgreg_do[3:0] = {flash_io3_di, flash_io2_di, flash_io1_di, flash_io0_di};
98	
99		always @(posedge clk) begin
100			softreset <= !config_en || cfgreg_we;
101			if (!resetn) begin
102				softreset <= 1;
103				config_en <= 1;
104				config_csb <= 0;
105				config_clk <= 0;
106				config_oe <= 0;
107				config_do <= 0;
108				config_ddr <= 0;
109				config_qspi <= 0;
110				config_cont <= 0;
111				config_dummy <= 8;
112			end else begin
113				if (cfgreg_we[0]) begin
114					config_csb <= cfgreg_di[5];
115					config_clk <= cfgreg_di[4];
116					config_do <= cfgreg_di[3:0];
117				end
118				if (cfgreg_we[1]) begin
119					config_oe <= cfgreg_di[11:8];
120				end
121				if (cfgreg_we[2]) begin
122					config_ddr <= cfgreg_di[22];
123					config_qspi <= cfgreg_di[21];
124					config_cont <= cfgreg_di[20];
125					config_dummy <= cfgreg_di[19:16];
126				end
127				if (cfgreg_we[3]) begin
128					config_en <= cfgreg_di[31];
129				end
130			end
131		end
132	
133		wire xfer_csb;
134		wire xfer_clk;
135	
136		wire xfer_io0_oe;
137		wire xfer_io1_oe;
138		wire xfer_io2_oe;
139		wire xfer_io3_oe;
140	
141		wire xfer_io0_do;
142		wire xfer_io1_do;
143		wire xfer_io2_do;
144		wire xfer_io3_do;
145	
146		reg xfer_io0_90;
147		reg xfer_io1_90;
148		reg xfer_io2_90;
149		reg xfer_io3_90;
150	
151		always @(negedge clk) begin
152			xfer_io0_90 <= xfer_io0_do;
153			xfer_io1_90 <= xfer_io1_do;
154			xfer_io2_90 <= xfer_io2_do;
155			xfer_io3_90 <= xfer_io3_do;
156		end
157	
158		assign flash_csb = config_en ? xfer_csb : config_csb;
159		assign flash_clk = config_en ? xfer_clk : config_clk;
160	
161		assign flash_io0_oe = config_en ? xfer_io0_oe : config_oe[0];
162		assign flash_io1_oe = config_en ? xfer_io1_oe : config_oe[1];
163		assign flash_io2_oe = config_en ? xfer_io2_oe : config_oe[2];
164		assign flash_io3_oe = config_en ? xfer_io3_oe : config_oe[3];
165	
166		assign flash_io0_do = config_en ? (config_ddr ? xfer_io0_90 : xfer_io0_do) : config_do[0];
167		assign flash_io1_do = config_en ? (config_ddr ? xfer_io1_90 : xfer_io1_do) : config_do[1];
168		assign flash_io2_do = config_en ? (config_ddr ? xfer_io2_90 : xfer_io2_do) : config_do[2];
169		assign flash_io3_do = config_en ? (config_ddr ? xfer_io3_90 : xfer_io3_do) : config_do[3];
170	
171		wire xfer_dspi = din_ddr && !din_qspi;
172		wire xfer_ddr = din_ddr && din_qspi;
173	
174		spimemio_xfer xfer (
175			.clk          (clk         ),
176			.resetn       (xfer_resetn ),
177			.din_valid    (din_valid   ),
178			.din_ready    (din_ready   ),
179			.din_data     (din_data    ),
180			.din_tag      (din_tag     ),
181			.din_cont     (din_cont    ),
182			.din_dspi     (xfer_dspi   ),
183			.din_qspi     (din_qspi    ),
184			.din_ddr      (xfer_ddr    ),
185			.din_rd       (din_rd      ),
186			.dout_valid   (dout_valid  ),
187			.dout_data    (dout_data   ),
188			.dout_tag     (dout_tag    ),
189			.flash_csb    (xfer_csb    ),
190			.flash_clk    (xfer_clk    ),
191			.flash_io0_oe (xfer_io0_oe ),
192			.flash_io1_oe (xfer_io1_oe ),
193			.flash_io2_oe (xfer_io2_oe ),
194			.flash_io3_oe (xfer_io3_oe ),
195			.flash_io0_do (xfer_io0_do ),
196			.flash_io1_do (xfer_io1_do ),
197			.flash_io2_do (xfer_io2_do ),
198			.flash_io3_do (xfer_io3_do ),
199			.flash_io0_di (flash_io0_di),
200			.flash_io1_di (flash_io1_di),
201			.flash_io2_di (flash_io2_di),
202			.flash_io3_di (flash_io3_di)
203		);
204	
205		reg [3:0] state;
206	
207		always @(posedge clk) begin
208			xfer_resetn <= 1;
209			din_valid <= 0;
210	
211			if (!resetn || softreset) begin
212				state <= 0;
213				xfer_resetn <= 0;
214				rd_valid <= 0;
215				din_tag <= 0;
216				din_cont <= 0;
217				din_qspi <= 0;
218				din_ddr <= 0;
219				din_rd <= 0;
220			end else begin
221				if (dout_valid && dout_tag == 1) buffer[ 7: 0] <= dout_data;
222				if (dout_valid && dout_tag == 2) buffer[15: 8] <= dout_data;
223				if (dout_valid && dout_tag == 3) buffer[23:16] <= dout_data;
224				if (dout_valid && dout_tag == 4) begin
225					rdata <= {dout_data, buffer};
226					rd_addr <= rd_inc ? rd_addr + 4 : addr;
227					rd_valid <= 1;
228					rd_wait <= rd_inc;
229					rd_inc <= 1;
230				end
231	
232				if (valid)
233					rd_wait <= 0;
234	
235				case (state)
236					0: begin
237						din_valid <= 1;
238						din_data <= 8'h ff;
239						din_tag <= 0;
240						if (din_ready) begin
241							din_valid <= 0;
242							state <= 1;
243						end
244					end
245					1: begin
246						if (dout_valid) begin
247							xfer_resetn <= 0;
248							state <= 2;
249						end
250					end
251					2: begin
252						din_valid <= 1;
253						din_data <= 8'h ab;
254						din_tag <= 0;
255						if (din_ready) begin
256							din_valid <= 0;
257							state <= 3;
258						end
259					end
260					3: begin
261						if (dout_valid) begin
262							xfer_resetn <= 0;
263							state <= 4;
264						end
265					end
266					4: begin
267						rd_inc <= 0;
268						din_valid <= 1;
269						din_tag <= 0;
270						case ({config_ddr, config_qspi})
271							2'b11: din_data <= 8'h ED;
272							2'b01: din_data <= 8'h EB;
273							2'b10: din_data <= 8'h BB;
274							2'b00: din_data <= 8'h 03;
275						endcase
276						if (din_ready) begin
277							din_valid <= 0;
278							state <= 5;
279						end
280					end
281					5: begin
282						if (valid && !ready) begin
283							din_valid <= 1;
284							din_tag <= 0;
285							din_data <= addr[23:16];
286							din_qspi <= config_qspi;
287							din_ddr <= config_ddr;
288							if (din_ready) begin
289								din_valid <= 0;
290								state <= 6;
291							end
292						end
293					end
294					6: begin
295						din_valid <= 1;
296						din_tag <= 0;
297						din_data <= addr[15:8];
298						if (din_ready) begin
299							din_valid <= 0;
300							state <= 7;
301						end
302					end
303					7: begin
304						din_valid <= 1;
305						din_tag <= 0;
306						din_data <= addr[7:0];
307						if (din_ready) begin
308							din_valid <= 0;
309							din_data <= 0;
310							state <= config_qspi || config_ddr ? 8 : 9;
311						end
312					end
313					8: begin
314						din_valid <= 1;
315						din_tag <= 0;
316						din_data <= config_cont ? 8'h A5 : 8'h FF;
317						if (din_ready) begin
318							din_rd <= 1;
319							din_data <= config_dummy;
320							din_valid <= 0;
321							state <= 9;
322						end
323					end
324					9: begin
325						din_valid <= 1;
326						din_tag <= 1;
327						if (din_ready) begin
328							din_valid <= 0;
329							state <= 10;
330						end
331					end
332					10: begin
333						din_valid <= 1;
334						din_data <= 8'h 00;
335						din_tag <= 2;
336						if (din_ready) begin
337							din_valid <= 0;
338							state <= 11;
339						end
340					end
341					11: begin
342						din_valid <= 1;
343						din_tag <= 3;
344						if (din_ready) begin
345							din_valid <= 0;
346							state <= 12;
347						end
348					end
349					12: begin
350						if (!rd_wait || valid) begin
351							din_valid <= 1;
352							din_tag <= 4;
353							if (din_ready) begin
354								din_valid <= 0;
355								state <= 9;
356							end
357						end
358					end
359				endcase
360	
361				if (jump) begin
362					rd_inc <= 0;
363					rd_valid <= 0;
364					xfer_resetn <= 0;
365					if (config_cont) begin
366						state <= 5;
367					end else begin
368						state <= 4;
369						din_qspi <= 0;
370						din_ddr <= 0;
371					end
372					din_rd <= 0;
373				end
374			end
375		end
376	endmodule
377	
378	module spimemio_xfer (
379		input clk, resetn,
380	
381		input            din_valid,
382		output           din_ready,
383		input      [7:0] din_data,
384		input      [3:0] din_tag,
385		input            din_cont,
386		input            din_dspi,
387		input            din_qspi,
388		input            din_ddr,
389		input            din_rd,
390	
391		output           dout_valid,
392		output     [7:0] dout_data,
393		output     [3:0] dout_tag,
394	
395		output reg flash_csb,
396		output reg flash_clk,
397	
398		output reg flash_io0_oe,
399		output reg flash_io1_oe,
400		output reg flash_io2_oe,
401		output reg flash_io3_oe,
402	
403		output reg flash_io0_do,
404		output reg flash_io1_do,
405		output reg flash_io2_do,
406		output reg flash_io3_do,
407	
408		input      flash_io0_di,
409		input      flash_io1_di,
410		input      flash_io2_di,
411		input      flash_io3_di
412	);
413		reg [7:0] obuffer;
414		reg [7:0] ibuffer;
415	
416		reg [3:0] count;
417		reg [3:0] dummy_count;
418	
419		reg xfer_cont;
420		reg xfer_dspi;
421		reg xfer_qspi;
422		reg xfer_ddr;
423		reg xfer_ddr_q;
424		reg xfer_rd;
425		reg [3:0] xfer_tag;
426		reg [3:0] xfer_tag_q;
427	
428		reg [7:0] next_obuffer;
429		reg [7:0] next_ibuffer;
430		reg [3:0] next_count;
431	
432		reg fetch;
433		reg next_fetch;
434		reg last_fetch;
435	
436		always @(posedge clk) begin
437			xfer_ddr_q <= xfer_ddr;
438			xfer_tag_q <= xfer_tag;
439		end
440	
441		assign din_ready = din_valid && resetn && next_fetch;
442	
443		assign dout_valid = (xfer_ddr_q ? fetch && !last_fetch : next_fetch && !fetch) && resetn;
444		assign dout_data = ibuffer;
445		assign dout_tag = xfer_tag_q;
446	
447		always @* begin
448			flash_io0_oe = 0;
449			flash_io1_oe = 0;
450			flash_io2_oe = 0;
451			flash_io3_oe = 0;
452	
453			flash_io0_do = 0;
454			flash_io1_do = 0;
455			flash_io2_do = 0;
456			flash_io3_do = 0;
457	
458			next_obuffer = obuffer;
459			next_ibuffer = ibuffer;
460			next_count = count;
461			next_fetch = 0;
462	
463			if (dummy_count == 0) begin
464				casez ({xfer_ddr, xfer_qspi, xfer_dspi})
465					3'b 000: begin
466						flash_io0_oe = 1;
467						flash_io0_do = obuffer[7];
468	
469						if (flash_clk) begin
470							next_obuffer = {obuffer[6:0], 1'b 0};
471							next_count = count - |count;
472						end else begin
473							next_ibuffer = {ibuffer[6:0], flash_io1_di};
474						end
475	
476						next_fetch = (next_count == 0);
477					end
478					3'b 01?: begin
479						flash_io0_oe = !xfer_rd;
480						flash_io1_oe = !xfer_rd;
481						flash_io2_oe = !xfer_rd;
482						flash_io3_oe = !xfer_rd;
483	
484						flash_io0_do = obuffer[4];
485						flash_io1_do = obuffer[5];
486						flash_io2_do = obuffer[6];
487						flash_io3_do = obuffer[7];
488	
489						if (flash_clk) begin
490							next_obuffer = {obuffer[3:0], 4'b 0000};
491							next_count = count - {|count, 2'b00};
492						end else begin
493							next_ibuffer = {ibuffer[3:0], flash_io3_di, flash_io2_di, flash_io1_di, flash_io0_di};
494						end
495	
496						next_fetch = (next_count == 0);
497					end
498					3'b 11?: begin
499						flash_io0_oe = !xfer_rd;
500						flash_io1_oe = !xfer_rd;
501						flash_io2_oe = !xfer_rd;
502						flash_io3_oe = !xfer_rd;
503	
504						flash_io0_do = obuffer[4];
505						flash_io1_do = obuffer[5];
506						flash_io2_do = obuffer[6];
507						flash_io3_do = obuffer[7];
508	
509						next_obuffer = {obuffer[3:0], 4'b 0000};
510						next_ibuffer = {ibuffer[3:0], flash_io3_di, flash_io2_di, flash_io1_di, flash_io0_di};
511						next_count = count - {|count, 2'b00};
512	
513						next_fetch = (next_count == 0);
514					end
515					3'b ??1: begin
516						flash_io0_oe = !xfer_rd;
517						flash_io1_oe = !xfer_rd;
518	
519						flash_io0_do = obuffer[6];
520						flash_io1_do = obuffer[7];
521	
522						if (flash_clk) begin
523							next_obuffer = {obuffer[5:0], 2'b 00};
524							next_count = count - {|count, 1'b0};
525						end else begin
526							next_ibuffer = {ibuffer[5:0], flash_io1_di, flash_io0_di};
527						end
528	
529						next_fetch = (next_count == 0);
530					end
531				endcase
532			end
533		end
534	
535		always @(posedge clk) begin
536			if (!resetn) begin
537				fetch <= 1;
538				last_fetch <= 1;
539				flash_csb <= 1;
540				flash_clk <= 0;
541				count <= 0;
542				dummy_count <= 0;
543				xfer_tag <= 0;
544				xfer_cont <= 0;
545				xfer_dspi <= 0;
546				xfer_qspi <= 0;
547				xfer_ddr <= 0;
548				xfer_rd <= 0;
549			end else begin
550				fetch <= next_fetch;
551				last_fetch <= xfer_ddr ? fetch : 1;
552				if (dummy_count) begin
553					flash_clk <= !flash_clk && !flash_csb;
554					dummy_count <= dummy_count - flash_clk;
555				end else
556				if (count) begin
557					flash_clk <= !flash_clk && !flash_csb;
558					obuffer <= next_obuffer;
559					ibuffer <= next_ibuffer;
560					count <= next_count;
561				end
562				if (din_valid && din_ready) begin
563					flash_csb <= 0;
564					flash_clk <= 0;
565	
566					count <= 8;
567					dummy_count <= din_rd ? din_data : 0;
568					obuffer <= din_data;
569	
570					xfer_tag <= din_tag;
571					xfer_cont <= din_cont;
572					xfer_dspi <= din_dspi;
573					xfer_qspi <= din_qspi;
574					xfer_ddr <= din_ddr;
575					xfer_rd <= din_rd;
576				end
577			end
578		end
579	endmodule
580

